// Modify a record in a table by primary key ID
template <typename T, typename IdT, typename ValueT>
void modify_eas_records_by_id(const std::string& table_name,
                              const IdT& record_id,
                              const std::string& col_name,
                              const ValueT& new_value) {
  using sqlgen::where;

  // Ensure the table_name matches T
  if constexpr (std::is_same_v<T, Student>) {
    if (table_name != "Student") return;
  } else if constexpr (std::is_same_v<T, Course>) {
    if (table_name != "Course") return;
  } else if constexpr (std::is_same_v<T, Score>) {
    if (table_name != "Score") return;
  } else if constexpr (std::is_same_v<T, Major>) {
    if (table_name != "Major") return;
  } else {
    return;
  }

  // Determine the primary key column name for each table
  const char* pk_col = nullptr;
  if constexpr (std::is_same_v<T, Student>) {
    pk_col = "SNo";
  } else if constexpr (std::is_same_v<T, Course>) {
    pk_col = "CID";
  } else if constexpr (std::is_same_v<T, Score>) {
    pk_col = "ScID";
  } else if constexpr (std::is_same_v<T, Major>) {
    pk_col = "MID";
  }

  if (pk_col == nullptr) return;

  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        // Build an update expression: set(col_name, new_value) where pk_col = record_id
        const auto c = col_name.c_str();
        const auto pk = pk_col;

        return (sqlgen::update<T>.set(c, new_value) |
                where(pk_c(pk) == record_id))(conn);
      })
      .value();
}

