        } else if (table_name == "Score") {
          // Score primary key is uint32_t: ScID (auto increment)
          const uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
          return (sqlgen::delete_from<Score> |
                  where("ScID"_c == id))(conn);
        } else if (table_name == "Major") {
          // Major primary key is uint32_t: MID
          const uint32_t id = static_cast<uint32_t>(std::stoul(record_id));
          return (sqlgen::delete_from<Major> |
                  where("MID"_c == id))(conn);
        } else {
          // Unsupported table: execute a no-op
          return sqlgen::exec(conn, ";");
        }
      })
      .value();
}
