```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database "test_db.sqlite"
  const auto conn_res = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }

  auto conn = *conn_res;

  // Drop the Product table if it exists, then create it
  const auto setup_res = conn
      .and_then(drop_table<Product> | if_exists)
      .and_then(create_table<Product>);
  if (!setup_res) {
    return false;
  }

  // Begin a transaction
  auto tx = conn.transaction();
  if (!tx) {
    return false;
  }

  // Insert all products within the transaction
  auto tx_conn = *tx;

  for (const auto& p : products) {
    const auto ins_res = insert_into<Product>(p)(tx_conn);
    if (!ins_res) {
      // Rollback on failure
      (void)tx.rollback();
      return false;
    }
  }

  // Commit transaction
  const auto commit_res = tx.commit();
  if (!commit_res) {
    return false;
  }

  return true;
}

}  // namespace batch_insert_products
