#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite connection to "test_db.sqlite"
  sqlite::connection conn{"test_db.sqlite"};

  // Begin a transaction
  auto tx = conn.transaction();

  // Build a delete statement using sqlgen:
  // DELETE FROM User WHERE last_login < DATE('2025-01-01');
  const auto stmt =
      sqlite::delete_from<User>() |
      where("last_login"_c < date("2025-01-01"));

  // Execute delete and get the number of affected rows
  const auto affected_rows = conn.execute(stmt);

  // Commit the transaction
  tx.commit();

  // Return the commit result / effect: number of deleted rows
  return static_cast<int>(affected_rows);
}

} // namespace delete_inactive_users
