```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  // Student table:
  // SNo      | varchar(10) | NOT NULL PRIMARY KEY
  // SName    | varchar(30) | NOT NULL
  // Sex      | int         | NULL DEFAULT 1
  // Birthday | datetime    | NULL
  // Major    | int         | NULL
  // Scorses  | float       | NULL DEFAULT 0
  // Remark   | text        | NULL
  struct Student {
    // Primary key (TEXT in SQLite)
    sqlgen::PrimaryKey<std::string> SNo;

    std::string SName;                   // NOT NULL

    // NULL DEFAULT 1  -> optional with default value 1 when inserting
    std::optional<int> Sex;

    // NULL datetime   -> mapped as optional string (ISO datetime text)
    std::optional<std::string> Birthday;

    std::optional<int> Major;           // NULL

    // NULL DEFAULT 0  -> optional with default value 0 when inserting
    std::optional<double> Scorses;

    std::optional<std::string> Remark;  // NULL
  };

  // Course table:
  // CID    | int         | NOT NULL auto_increment PK
  // CName  | varchar(30) | NOT NULL
  // Term   | int         | NULL DEFAULT 1
  // CTime  | int         | NULL
  // Credit | float       | NOT NULL DEFAULT 0
  struct Course {
    // AUTOINCREMENT primary key
    sqlgen::PrimaryKey<int> CID;

    std::string CName;                   // NOT NULL

    // NULL DEFAULT 1
    std::optional<int> Term;

    std::optional<int> CTime;           // NULL

    // NOT NULL DEFAULT 0
    double Credit;
  };

  // Score table:
  // SNo   | varchar(10) | NOT NULL (FK -> Student.SNo)
  // CID   | int         | NOT NULL (FK -> Course.CID)
  // Score | float       | NULL
  //
  // Composite primary key (SNo, CID) is not directly expressible with a single
  // sqlgen::PrimaryKey field, so we create the table with a raw SQL statement
  // and use this struct only for data mapping.
  struct Score {
    std::string SNo;
    int CID;
    std::optional<double> Score;
  };

  void design_eas_database() {
    using namespace sqlgen;

    // Open (or create) SQLite database "test_db.sqlite"
    auto db = sqlite::Database("test_db.sqlite");

    // Create Student and Course tables via sqlgen from the C++ structs.
    // sqlgen will infer reasonable SQLite types from the fields.
    db.create_table<Student>("Student");
    db.create_table<Course>("Course");

    // For Score we need a composite primary key and explicit foreign keys.
    // Use a raw SQL DDL statement to ensure the exact schema.
    const char* create_score_sql = R"SQL(
      CREATE TABLE IF NOT EXISTS Score (
        SNo   TEXT NOT NULL,
        CID   INTEGER NOT NULL,
        Score REAL,
        PRIMARY KEY (SNo, CID),
        FOREIGN KEY (SNo) REFERENCES Student(SNo),
        FOREIGN KEY (CID) REFERENCES Course(CID)
      );
    )SQL";

    db.exec(create_score_sql);
  }

}
