```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

// View mapping for the aggregated query result
struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create Course and Enrollment tables if they do not exist
  conn = conn.and_then(create_table<Course> | if_not_exists)
             .and_then(create_table<Enrollment> | if_not_exists);

  // Run the aggregation query and read into CourseStatsView
  const auto stats_view_vec = conn.and_then(
      [] (auto &c) {
        return c.read<std::vector<CourseStatsView>>(
            "SELECT c.title AS title, "
            "       COUNT(e.enrollment_id) AS student_count, "
            "       AVG(e.grade) AS avg_grade "
            "FROM Course c "
            "LEFT JOIN Enrollment e ON c.course_id = e.course_id "
            "GROUP BY c.course_id, c.title;");
      });

  // Map CourseStatsView results into CourseStats and return
  std::vector<CourseStats> result;
  if (!stats_view_vec) {
    return result;
  }

  result.reserve(stats_view_vec->size());
  for (const auto &row : *stats_view_vec) {
    result.push_back(CourseStats{
        .title = row.title,
        .student_count = row.student_count,
        .avg_grade = row.avg_grade});
  }

  return result;
}

}  // namespace query_course_enrollment_stats
