  // SELECT strftime('%Y-%m-%d', visit_time) AS visit_date,
  //        COUNT(*) AS total_visits,
  //        COUNT(DISTINCT url) AS unique_pages
  // FROM PageVisit
  // GROUP BY visit_date
  // ORDER BY visit_date;
  sqlite::create_view_as<DailyTrafficView>(
      conn,
      "SELECT strftime('%Y-%m-%d', visit_time) AS visit_date, "
      "       COUNT(*) AS total_visits, "
      "       COUNT(DISTINCT url) AS unique_pages "
      "FROM PageVisit "
      "GROUP BY visit_date "
      "ORDER BY visit_date");

  // Query the view and map the results into DailyTraffic structs
  const auto rows = sqlite::select<DailyTrafficView>(conn);

  std::vector<DailyTraffic> result;
  result.reserve(rows.size());
  for (const auto& row : rows) {
    result.push_back(DailyTraffic{
        .visit_date = row.visit_date,
        .total_visits = row.total_visits,
        .unique_pages = row.unique_pages});
  }

  return result;
}

}  // namespace query_daily_traffic_metrics
