std::vector<EmployeeManager> query_employee_hierarchy() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite connection to the given database file
  sqlite::connection conn{"test_db.sqlite"};

  // Build the self-join query:
  // SELECT e1.name AS employee, e2.name AS manager
  // FROM Employee e1
  // LEFT JOIN Employee e2 ON e1.manager_id = e2.emp_id;
  const auto query =
      read<std::vector<EmployeeManager>>(
          column<EmployeeManager>("employee"_c) =
              column<Employee>("e1"_t, "name"_c),
          column<EmployeeManager>("manager"_c) =
              column<Employee>("e2"_t, "name"_c)) |
      from<Employee>("e1"_t) |
      left_join<Employee>("e2"_t,
                          column<Employee>("e1"_t, "manager_id"_c) ==
                              column<Employee>("e2"_t, "emp_id"_c));

  // Execute and return results
  return sqlite::run(conn, query);
}

}  // namespace query_employee_hierarchy
