#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_high_value_orders {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct OrderView {
  static constexpr const char* tablename = "HighValueOrderView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> order_id;
  std::string name;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

std::vector<OrderView> query_high_value_orders() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite connection to the given database file.
  sqlgen::sqlite::Connection conn{"test_db.sqlite"};

  // Define a view that represents the required join + filter + ordering.
  // Equivalent SQL:
  // SELECT o.order_id, c.name, o.total_amount, o.order_date
  // FROM "Order" o
  // INNER JOIN Customer c ON o.customer_id = c.customer_id
  // WHERE o.total_amount > 1000
  // ORDER BY o.total_amount DESC;
  const auto create_view_query =
      sqlgen::CreateViewAs<OrderView>(
          sqlgen::Select{
              &Order::order_id,
              &Customer::name,
              &Order::total_amount,
              &Order::order_date}
          .from<Order, Customer>()
          .inner_join<Order, Customer>(&Order::customer_id,
                                       &Customer::customer_id)
          .where(&Order::total_amount > 1000.0)
          .order_by_desc(&Order::total_amount));

  // Create the view if it does not already exist.
  conn(create_view_query);

  // Query the view and return the results as a list of OrderView objects.
  return conn(sqlgen::SelectAllFrom<OrderView>{});
}

}  // namespace query_high_value_orders
