```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace query_product_sales_report {

struct Product {
  static constexpr const char* tablename = "Product";

  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  static constexpr const char* tablename = "Sale";

  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* viewname = "ProductSalesReport";
  static constexpr bool is_view = true;

  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build the view definition:
  // SELECT p.category, SUM(s.quantity) AS total_qty, SUM(s.amount) AS total_amt
  // FROM Product p
  // INNER JOIN Sale s ON p.product_id = s.product_id
  // GROUP BY p.category
  // HAVING total_amt > 5000;
  //
  // In sqlgen we explicitly repeat the aggregates in GROUP BY/HAVING:
  const auto view_query =
      create_view_as<ProductSalesReport>(
          read<ProductSalesReport>() |
          select("Product.category"_c,
                 sum("Sale.quantity"_c).as("total_qty"),
                 sum("Sale.amount"_c).as("total_amt")) |
          from<Product, Sale>() |
          where("Product.product_id"_c == "Sale.product_id"_c) |
          group_by("Product.category"_c,
                   sum("Sale.quantity"_c),
                   sum("Sale.amount"_c)) |
          having(sum("Sale.amount"_c) > 5000));

  // Open SQLite connection
  sqlgen::sqlite::Db db{"test_db.sqlite"};

  // Create or replace the view in the database
  db << view_query;

  // Query the view and materialize results into ProductSalesReport
  const auto query_view = read<std::vector<ProductSalesReport>>();

  std::vector<ProductSalesReport> rows;
  db << query_view >> rows;

  // Map to the requested CategoryReport type
  std::vector<CategoryReport> result;
  result.reserve(rows.size());
  for (const auto& r : rows) {
    result.push_back(CategoryReport{
        .category = r.category,
        .total_qty = r.total_qty,
        .total_amt = r.total_amt,
    });
  }

  return result;
}

}  // namespace query_product_sales_report
