#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  using namespace sqlgen;

  // Connect to the specific SQLite DB file
  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Helper lambda to execute a raw SQL statement and treat
  // "duplicate column name" as a non-fatal (already migrated) condition.
  auto exec_ignore_duplicate_column = [&](const std::string& sql) -> bool {
    auto res = conn->execute(sql);
    if (res) {
      return true;
    }

    // Inspect error message if available
