bool migration_add_column() {
  using namespace sqlgen;

  // Connect to the specific SQLite DB file
  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Helper lambda to execute a raw SQL statement and treat
  // "duplicate column name" as a non-fatal (already migrated) condition.
  auto exec_ignore_duplicate_column = [&](const std::string& sql) -> bool {
    auto res = conn->execute(sql);
    if (res) {
      return true;
    }

