```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  if (amount <= 0.0) {
    return false;
  }

  // Connect to the SQLite database "test_db.sqlite"
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = std::move(*conn_result);

  // Start a transaction
  auto tx_result = sqlgen::begin_transaction(conn);
  if (!tx_result) {
    return false;
  }
  auto tx = std::move(*tx_result);

  // Check if from_account has sufficient balance
  auto from_accounts_result =
      sqlgen::select_from<Account>(tx)
          .where("account_id"_c == from_account_id)
          .read<std::vector<Account>>();

  if (!from_accounts_result) {
    sqlgen::rollback(tx);
    return false;
  }

  const auto &from_accounts = *from_accounts_result;
  if (from_accounts.empty()) {
    sqlgen::rollback(tx);
    return false;
  }

  const auto &from_account = from_accounts.front();
  if (from_account.balance < amount) {
    sqlgen::rollback(tx);
    return false;
  }

  // Deduct from sender, ensuring sufficient funds in the UPDATE condition
  auto deduct_result =
      sqlgen::update<Account>(tx)
          .set("balance"_c = "balance"_c - amount)
          .where("account_id"_c == from_account_id &&
                 "balance"_c >= amount)
          .execute();

  if (!deduct_result) {
    sqlgen::rollback(tx);
    return false;
  }

  // Add to receiver
  auto add_result =
      sqlgen::update<Account>(tx)
          .set("balance"_c = "balance"_c + amount)
          .where("account_id"_c == to_account_id)
          .execute();

  if (!add_result) {
    sqlgen::rollback(tx);
    return false;
  }

  // Commit the transaction
  auto commit_result = sqlgen::commit(tx);
  if (!commit_result) {
    sqlgen::rollback(tx);
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
```

