  update_eas_table();
  {
    auto result = exec(conn, "SELECT 1 FROM pragma_table_info('Score') WHERE name='Grade' AND type='CHAR(1)';");
    ASSERT_TRUE(result);
  }

  {
    auto result = exec(conn, "SELECT 1 FROM pragma_table_info('Student') WHERE name='Age' AND type='INTEGER';");
