  }

  {
    auto result = exec(conn, "SELECT 1 WHERE NOT EXISTS (SELECT 1 FROM sqlite_master WHERE type='table' AND name='Major');");
    ASSERT_TRUE(result);
  }

  std::filesystem::remove(db_path);
  std::filesystem::remove("data");
