#pragma once

#include <filesystem>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

#include "eas_common.hpp"

namespace update_eas_table {

void update_eas_table() {
  // First ensure the original schema (with Major) exists.
  design_eas_database_with_major();

  // Connect to the SQLite database and perform the requested schema updates.
  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new column Grade to table Score, char(1), NOT NULL.
        //    SQLite uses TEXT; enforce NOT NULL and give a default so existing
        //    rows are valid.
        return sqlgen::exec(
                   conn,
                   "ALTER TABLE \"Score\" "
                   "ADD COLUMN \"Grade\" CHAR(1) NOT NULL DEFAULT 'F';")
            // 2. Modify column type of Age in Student to int, allowing NULL.
            //    SQLite has limited ALTER support; use a table-rebuild pattern.
            .and_then([&](auto&&) {
              return sqlgen::exec(
                  conn,
                  "BEGIN TRANSACTION;");
            })
            .and_then([&](auto&&) {
              // Create a new table with the desired Age column type.
              return sqlgen::exec(
                  conn,
                  "CREATE TABLE \"Student_new\" ("
                  "\"SNo\" TEXT NOT NULL PRIMARY KEY, "
                  "\"SName\" TEXT NOT NULL, "
                  "\"Sex\" INTEGER NOT NULL DEFAULT 1, "
                  "\"Birthday\" DATETIME, "
                  "\"Major\" INTEGER, "
                  "\"Scorses\" REAL, "
                  "\"Remark\" TEXT, "
                  "\"Age\" INTEGER"
                  ");");
            })
            .and_then([&](auto&&) {
              // Copy existing data; Age will be NULL for all existing rows.
              return sqlgen::exec(
                  conn,
                  "INSERT INTO \"Student_new\" "
                  "(\"SNo\", \"SName\", \"Sex\", \"Birthday\", "
                  "\"Major\", \"Scorses\", \"Remark\") "
                  "SELECT \"SNo\", \"SName\", \"Sex\", \"Birthday\", "
                  "\"Major\", \"Scorses\", \"Remark\" "
                  "FROM \"Student\";");
            })
            .and_then([&](auto&&) {
              // Drop the old Student table.
              return sqlgen::exec(conn, "DROP TABLE \"Student\";");
            })
            .and_then([&](auto&&) {
              // Rename the new table.
              return sqlgen::exec(
                  conn, "ALTER TABLE \"Student_new\" RENAME TO \"Student\";");
            })
            .and_then([&](auto&&) {
              return sqlgen::exec(conn, "COMMIT;");
            })
            // 3. Drop the Major table.
            .and_then([&](auto&&) {
              return sqlgen::exec(conn, "DROP TABLE IF EXISTS \"Major\";");
            });
      })
      .value();
}

} // namespace update_eas_table
