  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Try to use a single UPSERT-style statement. If sqlgen/sqlite
  // does not support generating `INSERT OR REPLACE` directly, we
  // fall back to raw SQL execution.
  //
  // Reference SQL:
  //   INSERT OR REPLACE INTO UserProfile (user_id, bio, avatar_url)
  //   VALUES (?, ?, ?);

  const char* sql =
      "INSERT OR REPLACE INTO UserProfile (user_id, bio, avatar_url) "
      "VALUES (?, ?, ?);";

  // sqlgen::sqlite::execute takes a connection and a prepared statement
  // with bound parameters; here we use the raw SQL helper.
  auto result = sqlite::execute(
      *conn,
      sql,
      u.user_id.value(),                 // PrimaryKey<T> usually exposes .value()
      u.bio ? *u.bio : std::optional<std::string>{},
