```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 *
 * Notes:
 * - SQLite does not support RIGHT JOIN directly. To include all departments
 *   (even those without projects), we conceptually need:
 *
 *     SELECT d.name, p.name
 *     FROM Project p
 *     RIGHT JOIN Department d ON p.department_id = d.department_id;
 *
 *   Since SQLite only has LEFT JOIN, we swap table roles:
 *
 *     SELECT d.name, p.name
 *     FROM Department d
 *     LEFT JOIN Project p ON d.department_id = p.department_id;
 *
 * - In this example, we let sqlgen execute the query and then map the
 *   results into DepProj. We keep project_name as an empty string when
 *   there is no corresponding project.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite".
  auto conn = sqlite::connect("test_db.sqlite");

  // Define a simple struct to read the joined data into.
  struct Row {
    std::optional<std::string> department_name;
    std::optional<std::string> project_name;
  };

  std::vector<DepProj> result;

  // If connection failed, just return empty result.
  if (!conn) {
    return result;
  }

  // Build a LEFT JOIN query from Department to Project, which semantically
  // corresponds to a RIGHT JOIN of Project to Department (all departments
  // included, projects may be missing).
  //
  // We use a raw SQL read here because the high-level join API for sqlgen
  // is not shown in the provided snippets.
  const char* sql =
      "SELECT Department.name AS department_name, "
      "       Project.name    AS project_name "
      "FROM Department "
      "LEFT JOIN Project ON Department.department_id = Project.department_id;";

  // Execute the query and map the rows.
  auto rows = conn->read<Row>(sql);

  for (const auto& r : rows) {
    DepProj dp;
    dp.department_name = r.department_name;
    // If there is no project, keep project_name as empty string.
    dp.project_name = r.project_name.value_or("");
    result.push_back(std::move(dp));
  }

  return result;
}

}  // namespace right_join_departments_projects
