/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build a complex query:
  // SELECT A.id, A.name, B.id, B.a_id, B.score
  // FROM A
  // JOIN B ON A.id = B.a_id
  // WHERE (B.score > 10) AND (A.name LIKE '%x%')
  // ORDER BY B.score DESC
  // LIMIT 5
  const auto query =
      read<std::vector<std::tuple<A, B>>> |
      join<B>("id"_c, "a_id"_c) |
      where("score"_c > 10.0 and "name"_c % "%x%") |
      order_by(desc("score"_c)) |
      limit(5);

  // Generate SQL string for SQLite (dry run: no execution).
  const auto sql = sqlgen::sqlite::to_sql(query);

  // Basic verification that the generated SQL contains expected clauses.
  // These checks are for debugging purposes only; they do not throw.
  const bool has_join =
      sql.find("JOIN") != std::string::npos &&
      sql.find("`B`") != std::string::npos;
  const bool has_where =
      sql.find("WHERE") != std::string::npos &&
      sql.find("`score` > 10") != std::string::npos &&
      sql.find("`name` LIKE '%x%'") != std::string::npos;
  const bool has_order =
      sql.find("ORDER BY") != std::string::npos &&
      sql.find("`score` DESC") != std::string::npos;
