namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Connects to the SQLite database "test_db.sqlite", ensures the Event table
 * exists, inserts the provided events, and runs a query that demonstrates
 * various temporal operations:
 *   - Extracting individual date/time components
 *   - Computing weekday information
 *   - Converting timestamps to Unix epoch
 *   - Computing day-level duration between start and end times
 *
 * Only events with a non-null end_time are returned in the analysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to (or create) the SQLite database file.
  auto db = Connection{"test_db.sqlite"};

  // Ensure the Event table exists in the database.
  db.exec(CreateTable<Event>{});

  // Insert the provided events. If they already exist, this may fail depending
  // on primary key usage; for demonstration purposes we simply attempt insert.
  if (!events.empty()) {
    db.exec(Insert<Event>{events});
  }

  // Build a query that demonstrates temporal analysis using SQLite functions.
  //
  // Notes about the SQL used:
  // - strftime('%d', ...) etc. extract date/time components.
  // - CAST(strftime('%s', ...) AS INTEGER) gives the Unix epoch seconds.
  // - (julianday(end_time) - julianday(start_time)) gives the duration in days.
  // - strftime('%w', ...) returns 0–6 for Sunday–Saturday, we keep this
  //   convention as "weekday".
  //
  // The reference SQL in the prompt uses DAY(), MONTH(), YEAR(), HOUR(), etc.
  // SQLite does not provide these directly, so we use strftime() as the
  // idiomatic alternative.
  const Query query = R"(
    SELECT
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) AS start_day,
      CAST(strftime('%m', start_time) AS INTEGER) AS start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) AS start_year,
      CAST(strftime('%H', start_time) AS INTEGER) AS start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) AS start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) AS start_second,
      CAST(strftime('%w', start_time) AS INTEGER) AS start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) AS start_epoch,
      (julianday(end_time) - julianday(start_time)) AS duration_days
    FROM Event
    WHERE end_time IS NOT NULL;
  )";

  // Execute the query and materialize results into TemporalAnalysis structs.
  // sqlgen will map columns by position into the struct fields.
  auto results = db.exec(SelectAs<TemporalAnalysis>{query});

  // The computed duration_days is already in days (double). We leave it as-is.
  // If the query returns NULL for duration_days (e.g., missing end_time),
  // sqlgen will propagate that into std::optional<double>.
  return results;
}

}  // namespace analyze_temporal_data
