```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Ensure the Inventory table exists. The problem statement says to assume it
  // exists, but this makes the example self‑contained and harmless if it
  // already exists.
  const auto table_res =
      conn.and_then(create_table<Inventory> | if_not_exists);
  if (!table_res) {
    return false;
  }
  conn = *table_res;

  // Perform UPSERT (INSERT OR REPLACE) for all provided items.
  auto upsert_res = conn.and_then(write(items) | or_replace);
  if (!upsert_res) {
    return false;
  }
  conn = *upsert_res;

  // Read back items to verify upsert behavior.
  const auto read_res = conn.and_then(read<std::vector<Inventory>>);
  if (!read_res) {
    return false;
  }

  const auto& stored_items = *read_res;

  // Basic verification:
  // 1. At least all items we attempted to upsert should be present.
  // 2. For each input item, there must be a row with the same primary key and
  //    matching data.
  for (const auto& input_item : items) {
    const auto it = std::find_if(
        stored_items.begin(), stored_items.end(),
        [&](const Inventory& db_item) {
          return db_item.item_id.value == input_item.item_id.value;
        });

    if (it == stored_items.end()) {
      // Missing item that was supposed to be upserted.
      return false;
    }

    if (it->name != input_item.name || it->quantity != input_item.quantity) {
      // Data mismatch – upsert did not correctly replace existing row.
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
