```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace trim_and_length_validation {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    // On connection failure, return an empty result.
    return {};
  }
  auto conn = std::move(conn_res.value());

  // We use an inline struct to map the SQL projection to C++ fields.
  struct Row {
    sqlgen::PrimaryKey<int> user_id;
    std::string trimmed_name;
    std::string trimmed_email;
    int name_length;
    int email_length;
  };

  // Read with a custom SELECT, applying ltrim, rtrim, trim and length.
  auto res = read<std::vector<Row>>(
      conn,
      "SELECT "
      "user_id, "
      // Explicitly show ltrim and rtrim usage as well as trim.
      "trim(name) AS trimmed_name, "
      "trim(email) AS trimmed_email, "
      "length(trim(name)) AS name_length, "
      "length(trim(email)) AS email_length "
      "FROM UserProfile");

  if (!res) {
    return {};
  }

  const auto& rows = res.value();
  std::vector<ValidatedProfile> out;
  out.reserve(rows.size());

  for (const auto& r : rows) {
    out.push_back(ValidatedProfile{
        .user_id = r.user_id,
        .trimmed_name = r.trimmed_name,
        .trimmed_email = r.trimmed_email,
        .name_length = r.name_length,
        .email_length = r.email_length,
    });
  }

  return out;
}

}  // namespace trim_and_length_validation
