  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

namespace detail {

// Result row used only for reading back computed SQL expressions.
struct OrderMetricsRow {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

}  // namespace detail

/**
 * Calculate per-item order metrics by loading the provided items into a SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and
 * estimated profit. Uses the external database file "test_db.sqlite".
 *
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(
    const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;
  using detail::OrderMetricsRow;

  // Connect to the SQLite database file as requested.
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    // On connection failure, return empty result.
    return {};
  }
  auto conn = std::move(conn_result.value());

  // Ensure the OrderItem table exists with the expected schema.
  // If the table already exists, if_not_exists prevents recreation.
  auto setup_result =
      (create_table<OrderItem> | if_not_exists)(conn);
  if (!setup_result) {
    return {};
  }

  // Insert provided items into the OrderItem table.
  for (const auto& item : items) {
    auto write_result = sqlgen::write(conn, item);
    if (!write_result) {
      // If an insert fails, stop and return what we have so far.
      // (Alternatively, this could skip failures, but we keep it simple.)
      return {};
    }
  }

  // Build a query that performs the SQL arithmetic operations and returns
  // the metrics as described.
  //
  // Reference SQL:
  // SELECT
  //   item_id,
  //   order_id,
  //   product_id,
  //   unit_price,
  //   quantity,
  //   discount_rate,
  //   tax_rate,
  //   (unit_price * quantity) as gross_total,
  //   (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100)) as discounted_total,
  //   (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100) * (1 + COALESCE(tax_rate, 0)/100)) as final_total,
  //   (unit_price * quantity / quantity) as unit_cost,
  //   (quantity % 10) as quantity_group,
  //   (unit_price * 0.3) as estimated_profit
  // FROM OrderItem;
  //
  // Using raw SQL here keeps the example focused on arithmetic/metrics.
  const char* sql =
      "SELECT "
      "  item_id, "
      "  order_id, "
      "  product_id, "
      "  unit_price, "
      "  quantity, "
      "  discount_rate, "
      "  tax_rate, "
      "  (unit_price * quantity) AS gross_total, "
      "  (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0)) AS "
      "discounted_total, "
      "  (unit_price * quantity * (1 - COALESCE(discount_rate, 0)/100.0) * "
      "   (1 + COALESCE(tax_rate, 0)/100.0)) AS final_total, "
      "  (unit_price * quantity / quantity) AS unit_cost, "
      "  (quantity % 10) AS quantity_group, "
      "  (unit_price * 0.3) AS estimated_profit "
      "FROM OrderItem";

  auto read_result =
      sqlgen::sqlite::read_raw<std::vector<OrderMetricsRow>>(conn, sql);
  if (!read_result) {
    return {};
  }

  const auto& rows = read_result.value();
  std::vector<OrderMetrics> metrics;
  metrics.reserve(rows.size());

  for (const auto& r : rows) {
    OrderMetrics m{};
    m.item_id = r.item_id;
    m.order_id = r.order_id;
    m.product_id = r.product_id;
    m.unit_price = r.unit_price;
    m.quantity = r.quantity;
    m.discount_rate = r.discount_rate.value_or(0.0);
    m.tax_rate = r.tax_rate.value_or(0.0);
    m.gross_total = r.gross_total;
    m.discounted_total = r.discounted_total;
    m.final_total = r.final_total;
    m.unit_cost = r.unit_cost;
    m.quantity_group = r.quantity_group;
    m.estimated_profit = r.estimated_profit;
    metrics.push_back(m);
  }

  return metrics;
}

}  // namespace calculate_order_metrics
