Customer read_single_record_by_id(int id) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn = sqlite::connect("test_db.sqlite");

  // Ensure the connection succeeded
  if (!conn) {
    throw std::runtime_error("Failed to connect to SQLite database: test_db.sqlite");
  }

  // Read from Customer where primary key (customer_id) matches the given id
  auto result =
      conn
          .and_then(sqlgen::read<std::vector<Customer>> |
                    where("customer_id"_c == id));

  if (!result) {
    throw std::runtime_error("Failed to execute read query for Customer");
  }

  auto customers = *result;
  if (customers.empty()) {
    throw std::runtime_error("No Customer found with the given id");
  }

  // Return the first (and expected only) matched row
  return customers.front();
}

}  // namespace read_single_record_by_id
