#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace join_orders_customers_payments {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct Payment {
  sqlgen::PrimaryKey<int> payment_id;
  int order_id;
  double amount;
};

struct Consolidated {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer_name;
  double amount;
};

/**
 * description: join_orders_customers_payments.
 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open a connection to the SQLite database "test_db.sqlite".
  auto conn = sqlite::connect("test_db.sqlite");

  // Build a SELECT query that:
  // 1. Selects Order.order_id, Customer.name, Payment.amount
  // 2. Performs inner joins:
  //      Order.customer_id = Customer.customer_id
  //      Payment.order_id  = Order.order_id
  // 3. Orders the results by Payment.amount in descending order.
  const auto query =
      Select<Consolidated>{}
          .from<Order>()
          .join<Customer>(Order{}.customer_id == Customer{}.customer_id)
          .join<Payment>(Payment{}.order_id == Order{}.order_id)
          .order_by(desc(Payment{}.amount));

  // Execute the query and return the consolidated results.
  return sqlite::select<Consolidated>(conn, query);
}

}  // namespace join_orders_customers_payments
