    (drop_table<Inventory> | if_exists)(conn);
    // Create table
    auto create_res = (create_table<Inventory> | if_not_exists)(conn);
    if (!create_res) {
      return false;
    }
  }

  // Bulk write the provided items
  auto write_res = sqlgen::write(conn, items);
  if (!write_res) {
    return false;
  }

  // Read back items where quantity > 50, ordered by quantity DESC
  // Using the sqlgen query DSL:
  // SELECT item_id, name, quantity, location FROM Inventory
