```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to (or create) the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure foreign keys are enforced (needed explicitly in SQLite)
  conn.execute("PRAGMA foreign_keys = ON;");

  // Drop tables if they already exist to have a clean slate
  conn.execute("DROP TABLE IF EXISTS Child;");
  conn.execute("DROP TABLE IF EXISTS Parent;");

  // Create the Parent and Child tables with the required constraints
  conn.execute(
      "CREATE TABLE Parent ("
      "  parent_id INTEGER PRIMARY KEY,"
      "  name TEXT NOT NULL"
      ");");

  conn.execute(
      "CREATE TABLE Child ("
      "  child_id INTEGER PRIMARY KEY,"
      "  parent_id INTEGER,"
      "  note TEXT,"
      "  FOREIGN KEY(parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE"
      ");");

  // Insert a parent row
  {
    Parent p{.parent_id = 1, .name = "parent1"};
    conn.insert(p);
  }

  // Insert one or more child rows referencing the parent
  {
    Child c1{.child_id = 1, .parent_id = 1, .note = "child1 of parent1"};
    Child c2{.child_id = 2, .parent_id = 1, .note = "child2 of parent1"};
    conn.insert(c1);
    conn.insert(c2);
  }

  // Delete the parent row; with ON DELETE CASCADE the children should be deleted
  conn.execute("DELETE FROM Parent WHERE parent_id = 1;");

  // Verify that no Child rows remain for parent_id = 1
  auto remaining_children =
      conn.select<Child>().where(&Child::parent_id == 1).execute();

  // If cascade delete worked, there should be zero matching Child rows
  return remaining_children.empty();
}

}  // namespace cascade_delete_demo
```

