```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the specific SQLite database file "test_db.sqlite"
  const auto conn_res = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = *conn_res;

  // 1. Create Account table (if not exists to make the function idempotent)
  if (!conn.and_then(create_table<Account> | if_not_exists)) {
    return false;
  }

  // Start with a clean slate for deterministic behavior: delete all rows
  if (!conn.and_then(delete_from<Account>)) {
    return false;
  }

  // Insert some sample accounts
  const std::vector<Account> accounts = {
      Account{.account_id = 1, .balance = 100.0, .status = "active"},
      Account{.account_id = 2, .balance = 200.0, .status = "inactive"},
      Account{.account_id = 3, .balance = 300.0, .status = "active"},
  };

  if (!conn.and_then(insert_into<Account>(accounts))) {
    return false;
  }

  // 2. Update balances and statuses using set(...)
  //
  // Example:
  //   - Increase balance by 50 for all active accounts
  //   - Set status to "premium" for accounts whose balance is >= 250
  //
  // NOTE: We use the sqlgen operations and literals API to build expressions.

  // Increase balance by 50 for "active" accounts.
  auto res_update_balance =
      conn.and_then(update<Account>(
          set("balance"_c = "balance"_c + 50.0),
          where("status"_c == "active")));

  if (!res_update_balance) {
    return false;
  }

  // Set status to "premium" where balance >= 250
  auto res_update_status =
      conn.and_then(update<Account>(
          set("status"_c = "premium"),
          where("balance"_c >= 250.0)));

  if (!res_update_status) {
    return false;
  }

  // 3. Verify changes persisted

  // Read back all accounts
  const auto read_res = conn.and_then(read<std::vector<Account>>);
  if (!read_res) {
    return false;
  }

  const auto &updated_accounts = *read_res;

  // We expect:
  // - account_id 1: balance 150, status "active" (balance < 250 so not premium)
  // - account_id 2: balance 200, status "inactive" (unchanged)
  // - account_id 3: balance 350, status "premium" (became premium)

  if (updated_accounts.size() != 3) {
    return false;
  }

  bool ok_id1 = false, ok_id2 = false, ok_id3 = false;

  for (const auto &acc : updated_accounts) {
    if (acc.account_id == 1) {
      // allow for floating point rounding tolerance
      ok_id1 = (std::abs(acc.balance - 150.0) < 1e-9 && acc.status == "active");
    } else if (acc.account_id == 2) {
      ok_id2 = (std::abs(acc.balance - 200.0) < 1e-9 &&
                acc.status == "inactive");
    } else if (acc.account_id == 3) {
      ok_id3 = (std::abs(acc.balance - 350.0) < 1e-9 &&
                acc.status == "premium");
    }
  }

  return ok_id1 && ok_id2 && ok_id3;
}

}  // namespace update_set_operations
```

