```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a
 * supplier and the name of a product, if any.
 *
 * This uses a FULL OUTER JOIN emulation for SQLite:
 *   - first part:  all suppliers, with matching products (LEFT JOIN)
 *   - second part: products whose supplier_id is NULL or missing in Supplier
 *                  (RIGHT-only part of FULL JOIN, synthesized manually)
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect explicitly to "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure the tables exist (no-op if already created)
  conn = conn.and_then(create_table<Supplier> | if_not_exists)
             .and_then(create_table<Product> | if_not_exists);

  // 1) LEFT JOIN part: all suppliers, with products when present
  //
  // SELECT s.name AS supplier_name, p.name AS product_name
  // FROM Supplier s
  // LEFT JOIN Product p ON s.supplier_id = p.supplier_id;
  //
  // NOTE: sqlgen does not have a built-in FULL OUTER JOIN, so we emulate it
  // with two queries and combine the results in C++.
  constexpr auto left_join_sql =
      "SELECT s.name AS supplier_name, p.name AS product_name "
      "FROM Supplier s "
      "LEFT JOIN Product p ON s.supplier_id = p.supplier_id";

  auto left_rows = conn.and_then(
      raw_query<std::vector<SupProd>>(left_join_sql));

  // 2) RIGHT-only part emulation:
  //
  // We want products whose supplier_id has no matching supplier row.
  //
  // SELECT '<unknown>' AS supplier_name, p.name AS product_name
  // FROM Product p
  // LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
  // WHERE s.supplier_id IS NULL;
  //
  // This covers:
  //  - products with a supplier_id that does not exist in Supplier
  //  - (if allowed) products with NULL supplier_id
  constexpr auto right_only_sql =
      "SELECT '<unknown>' AS supplier_name, p.name AS product_name "
      "FROM Product p "
      "LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id "
      "WHERE s.supplier_id IS NULL";

  auto right_only_rows = conn.and_then(
      raw_query<std::vector<SupProd>>(right_only_sql));

  // 3) Merge both parts to emulate FULL JOIN
  std::vector<SupProd> result;
  result.reserve(left_rows.size() + right_only_rows.size());
  result.insert(result.end(), left_rows.begin(), left_rows.end());
  result.insert(result.end(), right_only_rows.begin(), right_only_rows.end());

  return result;
}

}  // namespace full_join_suppliers_products
```

