#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to the specified SQLite database.
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables for Department and Employee if they do not already exist.
  conn = conn.and_then(create_table<Department> | if_not_exists)
             .and_then(create_table<Employee> | if_not_exists);

  // Clear any existing data so this function works deterministically
  conn = conn.and_then(execute(R"(DELETE FROM Department;)"))
             .and_then(execute(R"(DELETE FROM Employee;)"));

  // Insert provided departments and employees.
  conn = conn.and_then(insert(depts))
             .and_then(insert(emps));

  // Perform INNER JOIN: employees that have an assigned department.
  {
    auto inner = conn.and_then(read<std::vector<JoinResult>>(
        R"(SELECT d.department_name AS department_name,
                  e.first_name      AS first_name,
                  e.last_name       AS last_name,
                  e.salary          AS salary
           FROM Department d
           INNER JOIN Employee e ON d.department_id = e.department_id;)"
    ));
    if (inner) {
      analysis.inner_join_results = *inner;
    }
  }

  // Perform LEFT JOIN: all employees, even those without departments.
  {
    auto left = conn.and_then(read<std::vector<JoinResult>>(
        R"(SELECT d.department_name AS department_name,
                  e.first_name      AS first_name,
                  e.last_name       AS last_name,
                  e.salary          AS salary
           FROM Employee e
           LEFT JOIN Department d ON e.department_id = d.department_id;)"
    ));
    if (left) {
      analysis.left_join_results = *left;
    }
  }

  // Perform RIGHT JOIN equivalent in SQLite:
  // all departments, even those without employees.
  {
    auto right = conn.and_then(read<std::vector<JoinResult>>(
        R"(SELECT d.department_name AS department_name,
                  e.first_name      AS first_name,
                  e.last_name       AS last_name,
                  e.salary          AS salary
           FROM Department d
           LEFT JOIN Employee e ON d.department_id = e.department_id;)"
    ));
    if (right) {
      analysis.right_join_results = *right;
    }
  }

  // Perform FULL JOIN equivalent in SQLite:
  // union of LEFT JOIN (employees-driven) and RIGHT JOIN (departments-driven).
  {
    auto full = conn.and_then(read<std::vector<JoinResult>>(
        R"(SELECT d.department_name AS department_name,
                  e.first_name      AS first_name,
                  e.last_name       AS last_name,
                  e.salary          AS salary
           FROM Employee e
           LEFT JOIN Department d ON e.department_id = d.department_id
           UNION
           SELECT d2.department_name AS department_name,
                  e2.first_name      AS first_name,
                  e2.last_name       AS last_name,
                  e2.salary          AS salary
           FROM Department d2
           LEFT JOIN Employee e2 ON d2.department_id = e2.department_id;)"
    ));
    if (full) {
      analysis.full_join_results = *full;
    }
  }

  return analysis;
}

}  // namespace analyze_department_employees
