#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace delete_with_complex_condition {

struct User {
  sqlgen::PrimaryKey<int> id;
  int age;
  std::string status;
};

/**
 * This function demonstrates deleting with complex conditions.
 * Returns: std::string.
 */
inline std::string delete_with_complex_condition() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build a DELETE statement:
  //   DELETE FROM User WHERE age < 18 OR status = 'inactive';
  const auto stmt =
      delete_from<User> |
      where(("age"_c < 18) || ("status"_c == "inactive"));

  // Render and return the SQL string. The concrete connection is irrelevant
  // here; we just need something that can format SQL (sqlite in this case).
  return sqlite::to_sql(stmt);
}

}  // namespace delete_with_complex_condition
```

