  //   DELETE FROM User WHERE age < 18 OR status = 'inactive';
  const auto stmt =
      delete_from<User> |
      where(("age"_c < 18) || ("status"_c == "inactive"));

  // Render and return the SQL string. The concrete connection is irrelevant
  // here; we just need something that can format SQL (sqlite in this case).
  return sqlite::to_sql(stmt);
}

