```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <optional>

namespace coalesce_function {

struct Profile {
  sqlgen::PrimaryKey<int> id;
  std::optional<std::string> nickname;
};

struct NicknameResult {
  std::string display_name;
};

/**
 * This function demonstrates COALESCE usage.
 * Returns: query value.
 */
inline auto coalesce_function() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build a query that selects COALESCE(nickname, 'Anonymous')
  // and maps it into NicknameResult::display_name.
  //
  // We rely on sqlgen's expression/operators API; in sqlgen,
  // COALESCE is exposed as `coalesce(...)` taking column/expr
  // and a default value literal.
  //
  // The returned value is the sqlgen query object itself (a
  // composable pipeline), not a rendered SQL string.
  //
  // Example SQL that this corresponds to (for SQLite):
  //   SELECT COALESCE("nickname", 'Anonymous') AS "display_name"
  //   FROM "Profile";
  auto query =
      read<std::vector<NicknameResult>>(
          coalesce("nickname"_c, "Anonymous").as("display_name")) |
      from<Profile>();

  return query;
}

}  // namespace coalesce_function
```

