```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return {};
  }

  // Build and execute the query:
  // SELECT
  //   p.product_id,
  //   p.product_name,
  //   p.category,
  //   SUM(p.price * s.quantity) AS total_sales
  // FROM Product p
  // INNER JOIN Sales s ON p.product_id = s.product_id
  // GROUP BY p.product_id, p.product_name, p.category
  // ORDER BY total_sales DESC
  // LIMIT :limit_count;
  //
  // We rely on sqlgen expression utilities to construct this query and read the
  // result into std::vector<TopProduct>.

  const auto result =
      conn.and_then(
          // Construct a select query producing TopProduct rows
          select(
              // columns to project, matching TopProduct fields
              Product{}.product_id,
              Product{}.product_name,
              Product{}.category,
              sum(Product{}.price * Sales{}.quantity) >> "total_sales"_c
          )
          .from<Product>()
          .inner_join<Sales>(Product{}.product_id == Sales{}.product_id)
          .group_by(
              Product{}.product_id,
              Product{}.product_name,
              Product{}.category
          )
          .order_by(desc("total_sales"_c))
          .limit(static_cast<int>(limit_count))
      )
      .and_then(sqlgen::read<std::vector<TopProduct>>);

  if (!result) {
    return {};
  }

  return *result;
}

}  // namespace get_top_products
```

