namespace update_inventory_stock {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = conn_res.value();

  // Ensure Product table exists (IF NOT EXISTS semantics for sqlite)
  const auto create_stmt = transpilation::to_create_table<Product>();
  if (!exec(conn, create_stmt)) {
    return false;
  }

  // Begin transaction for atomic updates
  auto txn_res = begin_transaction(conn);
  if (!txn_res) {
    return false;
  }
  auto txn = txn_res.value();

  // Prepared statement for: UPDATE "Product" SET "stock" = "stock" + ? WHERE "product_id" = ?
  const auto update_stmt =
      update<Product>()
          .set("stock"_c = "stock"_c + parameter<int>())
          .where("product_id"_c == parameter<int>());

  auto prepared_res = txn->prepare(update_stmt);
  if (!prepared_res) {
    // Rollback on failure to prepare (best-effort; ignore rollback result)
    (void)rollback(txn);
    return false;
  }
  auto prepared = prepared_res.value();

  // Execute update for each received product_id -> quantity
  for (const auto& [pid, qty] : received) {
    // Bind parameters in order: quantity, product_id
    auto exec_res = prepared.exec(qty, pid);
    if (!exec_res) {
      (void)rollback(txn);
      return false;
    }
  }

  // Commit transaction
  auto commit_res = commit(txn);
  if (!commit_res) {
    (void)rollback(txn);
    return false;
  }

  return true;
}

