```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace create_view_order_summary {

struct Order {
  static constexpr const char* tablename = "Order";

  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
};

struct OrderItem {
  static constexpr const char* tablename = "OrderItem";

  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  double unit_price;
  int quantity;
};

struct OrderSummary {
  // NOTE: For views, sqlgen uses `viewname` and `is_view = true`.
  static constexpr const char* viewname = "OrderSummaryView";
  static constexpr bool is_view = true;

  sqlgen::PrimaryKey<int> order_id;
  std::string customer;
  double total;
};

/**
 * Description: This function demonstrates creating a view.
 * Returns: std::vector<OrderSummary>.
 */
std::vector<OrderSummary> create_view_order_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database "test_db.sqlite"
  auto db = sqlgen::sqlite::Database{"test_db.sqlite"};

  // Ensure the underlying tables exist (no-op if they already do).
  db.drop_table_if_exists<Order>();
  db.drop_table_if_exists<OrderItem>();
  db.create_table_if_not_exists<Order>();
  db.create_table_if_not_exists<OrderItem>();

  // Insert some sample data to make the view meaningful.
  const auto orders = std::vector<Order>{
      Order{.order_id = 1, .customer = "Alice"},
      Order{.order_id = 2, .customer = "Bob"},
  };

  const auto items = std::vector<OrderItem>{
      OrderItem{.item_id = 1, .order_id = 1, .unit_price = 10.0, .quantity = 2},
      OrderItem{.item_id = 2, .order_id = 1, .unit_price = 5.0, .quantity = 1},
      OrderItem{.item_id = 3, .order_id = 2, .unit_price = 20.0, .quantity = 1},
  };

  db.insert_into<Order>().values(orders).execute();
  db.insert_into<OrderItem>().values(items).execute();

  // Drop the view if it exists, then create it using CREATE VIEW AS.
  db.execute("DROP VIEW IF EXISTS OrderSummaryView");

  db.create_view_as<OrderSummary>(
      "SELECT o.order_id, o.customer, "
      "       SUM(oi.unit_price * oi.quantity) AS total "
      "FROM \"Order\" o "
      "INNER JOIN \"OrderItem\" oi ON o.order_id = oi.order_id "
      "GROUP BY o.order_id, o.customer");

  // Read from the view to verify data and return the results.
  auto results = db.select_from<OrderSummary>().execute();
  return results;
}

}  // namespace create_view_order_summary
```

