```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity
 * sold for each weekday (0=Sunday, 6=Saturday in SQLite's strftime('%w')).
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Open SQLite connection to the given database file.
  auto db = sqlite::Connection{"test_db.sqlite"};

  // We'll use a small helper struct to map aggregated query results.
  struct WeekdayRow {
    int weekday;
    int total_quantity;
  };

  // Prepare a raw SQL query that:
  // 1. Extracts weekday from sale_time using SQLite's strftime('%w', ...)
  // 2. Aggregates total quantity sold per weekday.
  //
  // NOTE: SQLite's strftime('%w', ...) returns 0 for Sunday through 6 for Saturday.
  const std::string query_sql =
      "SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday, "
      "       SUM(quantity) AS total_quantity "
      "FROM Sales "
      "GROUP BY weekday "
      "ORDER BY weekday;";

  const auto result =
      sqlite::raw_select<WeekdayRow>(db, query_sql);

  std::vector<WeekdayStats> stats;
  stats.reserve(result.size());

  for (const auto& row : result) {
    stats.push_back(WeekdayStats{
        .weekday = row.weekday,
        .total_quantity = row.total_quantity,
    });
  }

  return stats;
}

}  // namespace weekday_sales_analysis
