```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including
 * day, month, year, hour, minute, second, and duration in days. It also
 * groups by project and calendar week for reporting.
 *
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to the SQLite database "test_db.sqlite".
  // The tests for sqlite in this repo use sqlite::Credentials in this style.
  const auto credentials = Credentials{
      .file = "test_db.sqlite",
  };

  auto conn = Connection{credentials};

  // We will:
  // 1. Join Project and TimeLog.
  // 2. Extract date/time components from start_time.
  // 3. Compute duration in days between start_time and end_time.
  // 4. Group by project and week for reporting, using SQLite's strftime('%W')
  //    to determine the calendar week.
  //
  // For SQLite, we can't use DAY(), MONTH(), YEAR(), HOUR(), etc. directly;
  // instead we use strftime and CAST to INTEGER.
  //
  // Note: We return one row per project per week with average daily duration
  //       and representative date/time components of the week's first entry.
  //       The grouping is done in SQL via GROUP BY project and week.
  const std::string query =
      "SELECT "
      "  p.project_id AS project_id, "
      "  p.name AS name, "
      "  CAST(strftime('%d', t.start_time) AS INTEGER) AS day, "
      "  CAST(strftime('%m', t.start_time) AS INTEGER) AS month, "
      "  CAST(strftime('%Y', t.start_time) AS INTEGER) AS year, "
      "  CAST(strftime('%H', t.start_time) AS INTEGER) AS hour, "
      "  CAST(strftime('%M', t.start_time) AS INTEGER) AS minute, "
      "  CAST(strftime('%S', t.start_time) AS INTEGER) AS second, "
      // duration in days: difference in seconds divided by 86400.0
      "  AVG((julianday(t.end_time) - julianday(t.start_time))) AS duration_days "
      "FROM Project p "
      "INNER JOIN TimeLog t ON p.project_id = t.project_id "
      // Group by project and ISO week - here we use %W (week of year, Monday-based)
      "GROUP BY "
      "  p.project_id, "
      "  p.name, "
      "  strftime('%Y', t.start_time), "
      "  strftime('%W', t.start_time);";

  // Execute the query and map rows to TimeMetrics using sqlgen's generic query
  // facilities. sqlgen::sqlite::query<T>(conn, sql) will return std::vector<T>
  // where T is a plain struct with matching field names.
  //
  // The field names selected in the SQL (project_id, name, day, month, year,
  // hour, minute, second, duration_days) match the members of TimeMetrics.
  const auto metrics = query_vector<TimeMetrics>(conn, query);

  return metrics;
}

}  // namespace project_time_tracking
```

