namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open SQLite database
  auto db = sqlite::Database{"test_db.sqlite"};

  // Define table mappings
  auto users = make_table<User>("User");
  auto posts = make_table<Post>("Post");

  // Define expressions
  auto count_posts = count(posts->post_id);
  // length(content) is available via the SQL LENGTH() function
  auto avg_len = avg(length(posts->content));

  // Build and execute the query:
  // SELECT u.user_id, u.name, COUNT(p.post_id), AVG(LENGTH(p.content))
  // FROM User u
  // LEFT JOIN Post p ON u.user_id = p.user_id
  // GROUP BY u.user_id, u.name;
  auto query = select(
                   users->user_id,
                   users->name,
                   count_posts,
                   avg_len)
                   .from(users)
                   .left_join(posts, users->user_id == posts->user_id)
                   .group_by(users->user_id, users->name);

  return db.execute<Stats>(query);
}

}  // namespace group_by_with_aggregations
